package com.ruoyi.web.controller.mes;
import com.ruoyi.common.core.controller.BaseController; import com.ruoyi.common.core.domain.AjaxResult; import com.ruoyi.common.core.page.TableDataInfo; import com.ruoyi.mes.purchase.domain.PurchaseInbound; import com.ruoyi.mes.purchase.mapper.PurchaseInboundMapper; import jakarta.validation.Valid; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.Arrays;
@RestController @RequestMapping("/mes/purchase/inbound") public class PurchaseInboundController extends BaseController { private final PurchaseInboundMapper mapper; public PurchaseInboundController(PurchaseInboundMapper mapper){this.mapper=mapper;} @PreAuthorize("@ss.hasPermi('mes:purchaseInbound:list')") @GetMapping("/list") public TableDataInfo list(PurchaseInbound q){startPage();return getDataTable(mapper.selectList(q));} @PreAuthorize("@ss.hasPermi('mes:purchaseInbound:query')") @GetMapping("/{id}") public AjaxResult get(@PathVariable Long id){PurchaseInbound o=mapper.selectById(id);if(o!=null)o.setLines(mapper.selectLines(id));return success(o);} @PreAuthorize("@ss.hasPermi('mes:purchaseInbound:add')") @PostMapping public AjaxResult add(@Valid @RequestBody PurchaseInbound o){o.setCreateBy(getUsername());mapper.insert(o);if(o.getLines()!=null)o.getLines().forEach(x->{x.setInboundId(o.getId());mapper.insertLine(x);});return success(o.getId());} @PreAuthorize("@ss.hasPermi('mes:purchaseInbound:edit')") @PutMapping public AjaxResult edit(@Valid @RequestBody PurchaseInbound o){o.setUpdateBy(getUsername());return toAjax(mapper.update(o));} @PreAuthorize("@ss.hasPermi('mes:purchaseInbound:remove')") @DeleteMapping("/{ids}") public AjaxResult remove(@PathVariable Long[] ids){mapper.deleteLines(Arrays.asList(ids));return toAjax(mapper.deleteByIds(ids));} }
